/// <summary>
/// Classe-base de todas as condições de eventos de NPC. Cada subclasse
/// representa uma condição configurável no Inspector (estado do player ou do mundo).
///
/// Para adicionar uma nova condição: cria uma subclasse [System.Serializable]
/// e implementa Evaluate(). Ela aparece automaticamente no botão
/// "+ Adicionar Condição" do Inspector do NpcController.
/// </summary>
[System.Serializable]
public abstract class NpcCondition
{
    /// <summary>Devolve true se a condição está cumprida neste momento.</summary>
    public abstract bool Evaluate(NpcController npc);
}
